let header = 0b00011001;
let changemask = 0b00111111;

let health = global.get("health");
let sample = global.get("sample");
let batPeriod = global.get("batPeriod");
let tempPeriod = global.get("tempPeriod");
let humPeriod = global.get("humPeriod");
let co2Period = global.get("co2Period");

// Helper to split uint16 into high and low bytes
function toUint16Bytes(value) {
    return [(value >> 8) & 0xFF, value & 0xFF];
}

let bytes = [
    header,
    changemask,
    ...toUint16Bytes(health),
    ...toUint16Bytes(sample),
    ...toUint16Bytes(batPeriod),
    ...toUint16Bytes(tempPeriod),
    ...toUint16Bytes(humPeriod),
    ...toUint16Bytes(co2Period)
];

msg.payload = {
    downlinks: [{
        f_port: 1,
        frm_payload: Buffer.from(bytes).toString("base64")
    }]
};

return msg;
